render.css:
.kpi-trend-card { display: flex; flex-direction: column; gap: 8px; }
.kpi-trend-value { font-size: 32px; font-weight: 700; color: var(--ct-text-primary); font-variant-numeric: tabular-nums; }
.kpi-trend-meta { display: flex; align-items: center; gap: 8px; font-size: 12px; color: var(--ct-text-muted); }
.kpi-trend-arrow { color: var(--ct-text-strong); font-weight: 600; }
